INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('dried_fish', '烟熏鱼干', '稳健型标的。以规模化加工鱼肉干制品为基础，供应稳定、需求分散，价格波动低。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('fish_roe', '深海鱼卵', '高风险标的。依赖捕捞季、冷链周转和加工良率，供给弹性低，价格波动极大。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('fish_oil', '精炼鱼油', '投机品。受保健品订单、饲料厂采购和突发检验事件影响，可能出现大幅涨跌。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('fantasy_stable', '港湾盐封银鳞', '稳健型标的。渔港公会按标准盐封的银鳞鱼块，保质期长、消耗稳定，适合低波动配置。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('fantasy_high_risk', '龙鲤卵期约', '高风险标的。龙鲤产卵期短且受潮汐魔力影响，丰歉差距巨大，价格容易剧烈波动。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('fantasy_speculative', '海妖脂蜡', '投机品。由深海鱼脂炼成的灯蜡，船队传闻和祭典订单会触发异常行情。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('scifi_stable', '轨道鱼糜蛋白块', '稳健型标的。轨道养殖站量产的鱼糜蛋白块，规格统一、合约交割稳定。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('scifi_high_risk', '基因鲑胚样本', '高风险标的。基因鲑胚受实验批次、监管审查和孵化成功率影响，波动显著。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('scifi_speculative', '纳米鱼油悬液', '投机品。用于医疗涂层和微型机械润滑的鱼油悬液，技术消息会放大涨跌。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('xuanhuan_stable', '灵溪晒鱼符包', '稳健型标的。灵溪鱼干配合封存符包流通，宗门食堂长期采购，价格相对平稳。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('xuanhuan_high_risk', '赤鳞鱼籽丹材', '高风险标的。赤鳞鱼籽可入丹方，但成色受灵潮强弱影响，供需缺口变化大。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('xuanhuan_speculative', '鲲脂灯芯', '投机品。以巨鱼油脂炼制的灯芯，秘境开放和大宗炼器订单会引发跳涨跳跌。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('cthulhu_stable', '雾港腌鱼配给', '稳健型标的。雾港居民长期依赖的腌鱼配给，来源不多问，但日常需求稳定。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('cthulhu_high_risk', '黑礁鱼卵囊', '高风险标的。黑礁鱼卵囊只在异常潮位后出现，质量难以预测，价格波动极端。');
INSERT INTO "commodities" ("commodity_id", "name", "description") VALUES ('cthulhu_speculative', '梦潮鱼油', '投机品。带有梦潮沉淀物的鱼油，传闻、失踪航线和禁令都可能触发行情突变。');
